import lxml.etree

from flask import Flask, request

app = Flask(__name__)


@app.route('/parse_xml')
def parse_xml():
    '''
    Get the data from the request using 'xml_src'.
    Parse it as XML from the string.
    :return: The XML as a string.
    '''
    xml_src = request.args.get('xml_src') or request.form.get('xml_src')

    if not xml_src:
        return 'No XML source provided', 400

    parser = lxml.etree.XMLParser(resolve_entities=False)

    try:
        root = lxml.etree.fromstring(xml_src.encode('utf-8'), parser=parser)
        return lxml.etree.tostring(root, encoding='unicode')
    except lxml.etree.XMLSyntaxError:
        return 'Invalid XML', 400

